import axios from 'axios';


const BASE_URL="https://api.themoviedb.org/3";
export const Img_URL = "https://image.tmdb.org/t/p/original/";

export const fetchMovie=async(url)=>{
    const {data}= await axios.get(`${BASE_URL}/movie/${url}?api_key=${process.env.REACT_APP_API_KEY}`);
    return data;
};

export const fetchSearch=async(searchTerm,page)=>{
    const {data}= await axios.get(`${BASE_URL}/search/movie?api_key=${process.env.REACT_APP_API_KEY}&query=${searchTerm}&language=en-US&page=${page}`);
    return data;
};

export const fetchMovieDetails=async(id)=>{
    const response= await axios.get(`${BASE_URL}/movie/${id}?api_key=${process.env.REACT_APP_API_KEY}`);
    return response;
};

export const fetchGenres=async(id)=>{
    const response= await axios.get(`${BASE_URL}/genre/movie/list${id}?api_key=${process.env.REACT_APP_API_KEY}`);
    return response;
};
